module synchronizer(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);

    reg [3:0] data_reg;
    reg data_en_reg;
    reg data_en_reg2;
    reg data_en_reg3;

    always @(posedge clk_a or negedge arstn) begin
        if (!arstn) begin
            data_reg <= 4'b0;
            data_en_reg <= 1'b0;
            data_en_reg2 <= 1'b0;
            data_en_reg3 <= 1'b0;
        end else begin
            data_reg <= data_in;
            data_en_reg <= data_en;
            data_en_reg2 <= data_en_reg;
            data_en_reg3 <= data_en_reg2;
        end
    end

    always @(posedge clk_b or negedge brstn) begin
        if (!brstn) begin
            dataout <= 4'b0;
        end else if (data_en_reg3) begin
            dataout <= data_reg;
        end
    end

endmodule
